class Planner:
    """Task planner using LLM for decomposition."""

    def __init__(self, llm_service: BaseLLMService, tool_registry: ToolRegistry):
        self.llm = llm_service
        self.tool_registry = tool_registry

    def plan(self, user_query: str, task_type: str = "auto") -> List[TaskStep]:
        """
        Decompose user query into executable steps.

        Args:
            user_query: User's question
            task_type: Type of task (stock/market/macro/auto)

        Returns:
            List of TaskStep objects
        """
        tool_descriptions = self.tool_registry.list_tools()

        prompt = f"""你是一名投资分析专家。用户提出了以下问题：
{user_query}

可用工具：
{json.dumps(tool_descriptions, indent=2, ensure_ascii=False)}

请将这个问题分解为一系列步骤。输出JSON格式：
{{
    "steps": [
        {{
            "step_id": 1,
            "tool": "tool_name",
            "description": "这一步做什么",
            "params": {{"key": "value"}},
            "depends_on": []
        }}
    ]
}}

注意：
- 每一步必须使用可用工具
- params 包含工具所需参数
- depends_on 列出依赖的步骤ID"""

        try:
            response = "".join(self.llm.chat_stream(
                [{"role": "user", "content": prompt}],
                custom_system_prompt="你是一个JSON生成器，只输出JSON，不要其他文字"
            ))
        except Exception as e:
            error_msg = str(e)
            # Provide clearer error messages for common LLM connection issues
            if "Connection refused" in error_msg or "connect" in error_msg.lower():
                logger.error(f"LLM service unavailable (Connection refused): {e}")
                raise RuntimeError(
                    "LLM 服务不可用: 无法连接到 Ollama 服务器。请确保 Ollama 正在运行 (运行 'ollama serve')，"
                    "或者在 LLM 配置页面切换到其他 provider (如 OpenAI, Gemini)。"
                )
            elif "timeout" in error_msg.lower() or "timed out" in error_msg.lower():
                logger.error(f"LLM service timeout: {e}")
                raise RuntimeError(
                    f"LLM 服务响应超时: {error_msg}。请尝试切换到更快的 provider 或增加超时时间。"
                )
            else:
                logger.error(f"LLM call failed in planner: {e}")
                raise RuntimeError(f"LLM 服务错误: {str(e)}")

        return self._parse_response(response, user_query)

    def _parse_response(self, response: str, user_query: str = "") -> List[TaskStep]:
        """Parse LLM response with multiple strategies."""
        import re

        # Handle empty or None response
        if not response or not response.strip():
            logger.warning("Empty response from LLM, using fallback plan")
            return self._get_fallback_plan(user_query)

        # Strategy 1: Direct JSON
        try:
            data = json.loads(response)
            steps = data.get("steps", [])
            if steps:
                return [TaskStep(**step) for step in steps]
        except json.JSONDecodeError:
            pass

        # Strategy 2: Remove markdown
        cleaned = re.sub(r'^```json\s*', '', response.strip())
        cleaned = re.sub(r'\s*```$', '', cleaned)
        try:
            data = json.loads(cleaned)
            steps = data.get("steps", [])
            if steps:
                return [TaskStep(**step) for step in steps]
        except json.JSONDecodeError:
            pass

        # Strategy 3: Extract first JSON object
        match = re.search(r'\{[^{}]*\}', response, re.DOTALL)
        if match:
            try:
                data = json.loads(match.group())
                steps = data.get("steps", [])
                if steps:
                    return [TaskStep(**step) for step in steps]
            except:
                pass

        # Fallback: Return default plan
        logger.warning(f"Failed to parse LLM response: {response[:100]}..., using fallback plan")
        return self._get_fallback_plan(user_query)

