class StockDataCache:
    """Simple in-memory cache for stock data to avoid rate limiting."""

    def __init__(self, ttl_seconds: int = 300):  # 5 minutes default
        self._cache: Dict[str, Dict[str, Any]] = {}
        self._ttl = ttl_seconds

    def _make_key(self, code: str, period: str) -> str:
        return f"{code}:{period}"

    def get(self, code: str, period: str) -> Optional[Dict[str, Any]]:
        """Get cached data if not expired."""
        key = self._make_key(code, period)
        if key in self._cache:
            entry = self._cache[key]
            if time.time() - entry["timestamp"] < self._ttl:
                logger.debug(f"Cache hit for {code}:{period}")
                return entry["data"]
            else:
                del self._cache[key]
        return None

    def set(self, code: str, period: str, data: Dict[str, Any]):
        """Store data in cache."""
        key = self._make_key(code, period)
        self._cache[key] = {
            "data": data,
            "timestamp": time.time()
        }
        logger.debug(f"Cached data for {code}:{period}")


